const data = $input.first().json;

if (!data.filePath || !data.content) {
  throw new Error('Parámetros requeridos: filePath, content');
}

// Normalize: remove /workspace/ prefix if present — cloud uses repo-relative paths
let filePath = data.filePath.replace(/^\/workspace\//, '');

return [{ json: { filePath, content: data.content } }];

const githubCheck = $input.first().json;
const params = $('Validar Parámetros').first().json;

const base64Content = Buffer.from(params.content).toString('base64');
const sha = githubCheck.sha || null; // null if file doesn't exist yet

return [{ json: { filePath: params.filePath, base64Content, sha } }];

const token = $vars.TELEGRAM_BOT_TOKEN || '';
const chatId = $vars.TELEGRAM_CHAT_ID || '';

if (!token || !chatId || token === 'TU_TOKEN_AQUI' || chatId === 'TU_CHAT_ID_AQUI') {
  console.log('[SUB-002] Telegram no configurado. Mensaje descartado:', $input.first().json.mensaje);
  return [{ json: { sent: false, reason: 'telegram_not_configured' } }];
}

return [{ json: { mensaje: $input.first().json.mensaje, token, chatId, send: true } }];

const data = $input.first().json;

if (!data.templatePath) {
  throw new Error('Parámetro requerido: templatePath');
}
if (!data.variables || typeof data.variables !== 'object') {
  throw new Error('Parámetro requerido: variables (objeto con claves y valores)');
}

// Normalize: remove /workspace/ prefix
let templatePath = data.templatePath.replace(/^\/workspace\//, '');

return [{ json: { templatePath, variables: data.variables } }];

let template = Buffer.from($json.content, 'base64').toString('utf8');
const variables = $('Validar Parámetros').first().json.variables;

for (const [key, value] of Object.entries(variables)) {
  const placeholder = new RegExp(`\\{\\{${key}\\}\\}`, 'g');
  template = template.replace(placeholder, value || '');
}

return [{ json: { content: template, variables } }];

const githubResponse = $input.first().json;
const input = $('Ejecutar por Workflow').first().json;

const timestamp = input.timestamp || new Date().toISOString();
const date = timestamp.split('T')[0];
const time = (timestamp.split('T')[1] || '00:00').substring(0, 5);
const evento = input.evento || 'EVENTO';
const pieza = input.pieza || '—';
const detalles = input.detalles || '';

const logLine = `| ${date} | ${time} | ${evento} | ${pieza} | ${detalles} |`;

let existingContent = '';
let sha = null;

if (githubResponse.content) {
  // File exists — decode and get SHA
  existingContent = Buffer.from(githubResponse.content, 'base64').toString('utf8');
  sha = githubResponse.sha;
} else {
  // New file
  existingContent = '# FG Operations Log\n\n| Fecha | Hora | Evento | Pieza | Detalles |\n|-------|------|--------|-------|----------|\n';
}

const newContent = existingContent + logLine + '\n';
const base64Content = Buffer.from(newContent).toString('base64');

return [{ json: { base64Content, sha, logLine, logged: true } }];

// GitHub returns array of files for directory listing
const files = Array.isArray($input.first().json) ? $input.first().json : [];
const body = $('Webhook Intake').first().json.body;

let maxNum = 0;
for (const file of files) {
  const match = (file.name || '').match(/^P1_(\d{3})/);
  if (match) {
    const num = parseInt(match[1], 10);
    if (num > maxNum) maxNum = num;
  }
}

const nextNum = String(maxNum + 1).padStart(3, '0');
const idPieza = `P1_${nextNum}`;

const pilares = {
  'GD': 'Geopolitik Drop',
  'BB': 'Bass & Borders',
  'FG': 'Frecuencia Global',
  'BP': 'Behind the Policy'
};

const today = new Date().toISOString().split('T')[0];
const weekNum = Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / 604800000);
const weekId = `W${String(weekNum).padStart(2, '0')}`;
const idCompleto = `FG-${new Date().getFullYear()}-${weekId}-${nextNum}`;

return [{
  json: {
    idPieza,
    idCompleto,
    nextNum,
    titulo: body.titulo,
    pilar: body.pilar,
    pilarNombre: pilares[body.pilar] || body.pilar,
    angulo: body.angulo || '',
    formato: body.formato || 'carousel',
    plataformas: body.plataformas || 'Instagram',
    autor: body.autor || 'Farid Mohammadi',
    deadline: body.deadline || '',
    fecha: today
  }
}];

const template = Buffer.from($json.content, 'base64').toString('utf8');
const data = $('Calcular Siguiente ID').first().json;

let content = template;
content = content.replace(/\{\{ID_PIEZA\}\}/g, data.idCompleto);
content = content.replace(/\{\{FECHA\}\}/g, data.fecha);
content = content.replace(/\{\{TITULO\}\}/g, data.titulo);
content = content.replace(/\{\{PILAR_MARCADO\}\}/g, data.pilarNombre);
content = content.replace(/\{\{ANGULO\}\}/g, data.angulo);
content = content.replace(/\{\{FORMATO\}\}/g, data.formato);
content = content.replace(/\{\{PLATAFORMAS\}\}/g, data.plataformas);
content = content.replace(/\{\{AUTOR\}\}/g, data.autor);
content = content.replace(/\{\{DEADLINE\}\}/g, data.deadline);

return [{ json: { content, idPieza: data.idPieza, ...data } }];

const data = $input.first().json;
const base64Content = Buffer.from(data.content).toString('base64');
return [{ json: { ...data, base64Content } }];

const res = $input.first().json;
let tracker = {};
let sha = null;

if (res.content) {
  try { tracker = JSON.parse(Buffer.from(res.content, 'base64').toString('utf8')); } catch(e) { tracker = {}; }
  sha = res.sha || null;
}

const body = $('Webhook Register').first().json.body;
const pieza = body.pieza;
const estado = body.estado;

const estadosValidos = ['BRIEF_READY','RESEARCH_DONE','SCRIPT_DONE','DESIGN_DONE','QA_PASS','PUBLISHED'];
if (!estadosValidos.includes(estado)) {
  throw new Error(`Estado inválido: ${estado}. Válidos: ${estadosValidos.join(', ')}`);
}

if (!tracker[pieza]) tracker[pieza] = { historial: [] };
const ts = new Date().toISOString();
tracker[pieza].estado_actual = estado;
tracker[pieza].ultima_actualizacion = ts;
tracker[pieza].historial = tracker[pieza].historial || [];
tracker[pieza].historial.push({ estado, timestamp: ts });

const base64Content = Buffer.from(JSON.stringify(tracker, null, 2)).toString('base64');
return [{ json: { pieza, estado, timestamp: ts, tracker_actualizado: true, base64Content, ...(sha ? { sha } : {}) } }];

const pieza = $('Webhook QA').first().json.body.pieza;
const briefContent = Buffer.from($json.content, 'base64').toString('utf8');

let titulo = '', pilar = '', formato = '', plataformas = '';
for (const line of briefContent.split('\n')) {
  if (line.includes('**Título:**')) titulo = line.split('**Título:**')[1]?.trim() || titulo;
  if (line.includes('**Pilar:**')) pilar = line.split('**Pilar:**')[1]?.trim() || pilar;
  if (line.includes('**Formato:**')) formato = line.split('**Formato:**')[1]?.trim() || formato;
  if (line.includes('**Plataforma(s):**')) plataformas = line.split('**Plataforma(s):**')[1]?.trim() || plataformas;
}

return [{ json: { pieza, titulo, pilar, formato, plataformas } }];

