return [{ json: { base64Content, ...(sha ? { sha } : {}), ...$('Formatear Log').first().json } }];

const res = $input.first().json;

if (!res.content) {
  return [{ json: { resumen: 'Sin piezas registradas en el tracker.', stats: {}, trackerSha: null, trackerBase64: null } }];
}

let tracker = {};
try { tracker = JSON.parse(Buffer.from(res.content, 'base64').toString('utf8')); } catch(e) {}
