const pieza = $('Webhook Prep').first().json.body.pieza;
const brief = Buffer.from($json.content, 'base64').toString('utf8');

function parseField(content, fieldName) {
  const lines = content.split('\n');
  for (const line of lines) {
    if (line.includes('**' + fieldName + '**')) {
      const parts = line.split('|');
      if (parts.length >= 4) return parts[2].trim();
    }
  }
  return '';
}

const titulo = parseField(brief, 'Título de trabajo');
const pilarNombre = parseField(brief, 'Pilar');
const angulo = parseField(brief, 'Ángulo FG');
const tesis = parseField(brief, 'Tesis central');
const formato = parseField(brief, 'Formato principal');
const plataformas = parseField(brief, 'Plataforma(s)');

const pilarMap = {
  'geopolitik drop': 'GD', 'bass & borders': 'BB',
  'frecuencia global': 'FG', 'blueprint': 'BP', 'behind the policy': 'BP'
};
const pilarCode = pilarMap[(pilarNombre || '').toLowerCase()] || 'FG';

return [{ json: { pieza, titulo, pilarNombre, pilarCode, angulo, tesis, formato, plataformas } }];

const d = $input.first().json;
const { pieza, titulo, pilarCode, angulo, tesis, formato, plataformas } = d;

const hashtagSets = {
  GD: ['#GeopolitikDrop', '#Geopolitica', '#RelacionesInternacionales', '#AsesorInternacional', '#FrecuenciaGlobal'],
  BB: ['#BassAndBorders', '#CulturaGlobal', '#MusicaYGeopolitica', '#BordesTonales', '#FrecuenciaGlobal'],
  FG: ['#FrecuenciaGlobal', '#AnalisisInternacional', '#Geopolitica', '#PoliticaGlobal'],
  BP: ['#BehindThePolicy', '#Geopolitica', '#AnalisisPolitico', '#PoliticaInternacional', '#FrecuenciaGlobal']
};

const tags = hashtagSets[pilarCode] || hashtagSets.FG;
const tagsFull = tags.join(' ');
const tagsShort = tags.slice(0, 3).join(' ');
const desc = (tesis && tesis !== '[pendiente de desarrollo]') ? tesis : (angulo || '');

let xCopy = titulo + '\n\n' + tagsShort;
if (xCopy.length > 280) {
  const maxTitle = 280 - tagsShort.length - 4;
  xCopy = titulo.substring(0, maxTitle) + '...\n\n' + tagsShort;
}
xCopy = xCopy.substring(0, 280);

const igTags = tags.concat(['#AnalisisInternacional', '#ContenidoGeopolitico', '#InformacionGlobal']).join(' ');
const igCaption = titulo + (desc ? '\n\n' + desc : '') + '\n\n\uD83D\uDCCC Análisis por Frecuencia Global.\n\n' + igTags;
const liCaption = titulo + (desc ? '\n\n' + desc : '') + '\n\nEn Frecuencia Global analizamos el cruce entre geopolítica, cultura e información global.\n\n' + tagsFull;
const hookTT = titulo.length > 200 ? titulo.substring(0, 197) + '...' : titulo;
const ttCaption = (hookTT + ' ' + tags.slice(0, 3).join(' ')).substring(0, 300);

return [{ json: Object.assign({}, d, { xCopy, igCaption, liCaption, ttCaption, tagsFull, tagsShort, xCharCount: xCopy.length, ttCharCount: ttCaption.length }) }];

const trackerRes = $input.first().json;
const briefData = $('Leer Brief').first().json;
const copyData = $('Generar Copy por Plataforma').first().json;

let tracker = {};
